import { Component, Element, h, Host, Prop } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

export type WdprCameraScannerAspect = '1x1' | '16x9';
export type WdprCameraScannerSize = 'sm' | 'md' | 'lg';

@Component({
  tag: 'wdpr-camera-scanner',
  shadow: true,
})
export class WdprCameraScanner {
  @Element() el!: HTMLWdprCameraScannerElement;

  @Prop() instruction: string = 'Center the Code Here';

  @Prop({ reflect: true }) aspect: WdprCameraScannerAspect = '1x1';

  /**
   * Preset sizes from design system
   */
  @Prop() size: WdprCameraScannerSize = 'md';

  /**
   * Custom width (overrides size). Example: '280px', 'min(90vw, 360px)'
   */
  @Prop() width?: string;

  private sizeMap: Record<WdprCameraScannerSize, string> = {
    sm: 'w-[240px]',
    md: 'w-[320px]',
    lg: 'w-[400px]',
  };

  render() {
    const resolvedWidthClass = this.width ? undefined : this.sizeMap[this.size];

    const root = customTwMerge(
      'relative select-none overflow-hidden mx-auto', // center horizontally
      resolvedWidthClass,
      this.aspect === '16x9' ? 'aspect-video' : 'aspect-square'
    );

    const bounds = 'relative w-full h-full box-border';

    const corner = 'absolute w-dimension-450 h-dimension-450';

    const barBase = 'absolute bg-component-camera-scan-stroke rounded-025';
    const hBar = customTwMerge(barBase, 'h-dimension-050 w-dimension-400');
    const vBar = customTwMerge(barBase, 'w-dimension-050 h-dimension-400');

    const hintWrap =
      'absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 text-center text-text-inverse';
    const hintText = 'text-heading-xxsmall-alt leading-tight';

    const inset = '0';

    return (
      <Host>
        <div
          class={root}
          part="root"
          role="application"
          aria-label="Camera scanner guide"
          style={this.width ? { width: this.width } : undefined}
        >
          <div class={bounds} part="bounds">
            {/* Top-left */}
            <div class={customTwMerge(corner, `top-${inset} left-${inset}`)} part="corner-tl">
              <span class={customTwMerge(hBar, `top-${inset} left-${inset}`)} />
              <span class={customTwMerge(vBar, `top-${inset} left-${inset}`)} />
            </div>

            {/* Top-right */}
            <div class={customTwMerge(corner, `top-${inset} right-${inset}`)} part="corner-tr">
              <span class={customTwMerge(hBar, `top-${inset} right-${inset}`)} />
              <span class={customTwMerge(vBar, `top-${inset} right-${inset}`)} />
            </div>

            {/* Bottom-left */}
            <div class={customTwMerge(corner, `bottom-${inset} left-${inset}`)} part="corner-bl">
              <span class={customTwMerge(hBar, `bottom-${inset} left-${inset}`)} />
              <span class={customTwMerge(vBar, `bottom-${inset} left-${inset}`)} />
            </div>

            {/* Bottom-right */}
            <div class={customTwMerge(corner, `bottom-${inset} right-${inset}`)} part="corner-br">
              <span class={customTwMerge(hBar, `bottom-${inset} right-${inset}`)} />
              <span class={customTwMerge(vBar, `bottom-${inset} right-${inset}`)} />
            </div>

            <div class={hintWrap} part="hint" aria-live="polite">
              <div class={hintText}>{this.instruction}</div>
            </div>
          </div>
        </div>
      </Host>
    );
  }
}